import React, { useRef, useEffect, useState } from 'react';

import * as classes from './SnapScroll.module.scss';

const STIFFNESS = 7;

interface Props {
	active: number;
	className?: string;
	children: React.ReactNode;
}

const SnapScroll = ({ active, className, children }: Props) => {
	const [startX, setStartX] = useState<number>(0);
	const [scrollLeft, setScrollLeft] = useState<number>(0);

	const [isDragging, setIsDragging] = useState<boolean>(false);

	const selected = useRef<number>(active);

	const lastPageX = useRef<number>();

	const parent = useRef<HTMLUListElement>(null);

	function startHandler(event: React.MouseEvent | React.TouchEvent) {
		setIsDragging(true);

		const pageX = (event as React.MouseEvent).pageX || (event as React.TouchEvent).touches[0].pageX;

		setStartX(pageX);
		setScrollLeft(parent.current!.scrollLeft);
	}

	function moveHandler(event: React.MouseEvent | React.TouchEvent) {
		if (!isDragging) return;

		lastPageX.current = (event as React.TouchEvent).touches?.[0].pageX;

		const pageX = (event as React.MouseEvent).pageX || (event as React.TouchEvent).touches[0].pageX;

		const difference = pageX - startX;

		parent.current!.scrollLeft = scrollLeft - difference;
	}

	function endHandler(event: React.MouseEvent | React.TouchEvent) {
		setIsDragging(false);

		const pageX = (event as React.MouseEvent).pageX || lastPageX.current!;

		const isMovedRight = startX > pageX;
		const isMovedLeft = startX < pageX;

		console.log({ startX, pageX });

		const draggedEnough = Math.abs(startX - pageX) > STIFFNESS * 10;

		let element = parent.current!.childNodes[selected.current] as Element;

		if (isMovedRight) {
			const isNewElement = selected.current + 1 < parent.current!.children.length;

			if (isNewElement && draggedEnough) {
				element = parent.current!.childNodes[selected.current + 1] as Element;

				selected.current = selected.current + 1;
			}
		} else if (isMovedLeft) {
			const isNewElement = selected.current > 0;

			if (isNewElement && draggedEnough) {
				element = parent.current!.childNodes[selected.current - 1] as Element;

				selected.current = selected.current - 1;
			}
		} else {
			return;
		}

		const elementRect = element.getBoundingClientRect();

		parent.current!.scrollTo({
			left: elementRect.left + scrollLeft + startX - pageX,
			behavior: 'smooth'
		});
	}

	useEffect(() => {
		selected.current = active;

		if (active === 0) {
			parent.current!.scrollTo({ left: 0, behavior: 'smooth' });

			return;
		}

		const child = parent.current!.children[active] as HTMLElement;

		parent.current!.scrollTo({ left: child.offsetLeft, behavior: 'smooth' });
	}, [active]);

	return (
		<ul
			className={[classes.SnapScroll, className].join(' ')}
			onMouseDown={startHandler}
			onMouseUp={endHandler}
			onMouseMove={moveHandler}
			onTouchStart={startHandler}
			onTouchMove={moveHandler}
			onTouchEnd={endHandler}
			ref={parent}>
			{React.Children.map(children, (child) => {
				if (React.isValidElement(child)) {
					return React.cloneElement(child as React.ReactElement<any>);
				}

				return child;
			})}
		</ul>
	);
};

export default SnapScroll;
